// SPDX-License-Identifier: Apache-2.0

package chisel3.naming

/** Experimental! Please don't use. */
trait HasCustomIdentifier {
  protected val customDefinitionIdentifierProposal: String
  final def customDefinitionIdentifier: String = IdentifierProposer.filterProposal(customDefinitionIdentifierProposal)
}

/** Experimental! Please don't use. */
object IdentifierProposer {

  // Any proposal needs valid characters
  // E.g. `chisel3.internal.Blah@123412` -> `chisel3_internal_Blah`
  // E.g. `(Foo)` -> `Foo`
  // E.g. `Foo(1)` -> `Foo_1`
  def filterProposal(s: String): String = {
    def legalStartOrEnd(c: Char) = (c >= 'a' && c <= 'z') || (c >= 'A' && c <= 'Z') || (c >= '0' && c <= '9')
    def legal(c:           Char) = legalStartOrEnd(c) || c == '_'
    def terminate(c:       Char) = c == '@'
    var firstOkChar: Int = -1
    var lastOkChar:  Int = 0
    var finalChar:   Int = -1
    for (i <- (0 until s.length)) {
      if (finalChar != -1 && finalChar < i) {}
      else {
        if (terminate(s(i))) finalChar = i
        else {
          if (legalStartOrEnd(s(i))) {
            lastOkChar = i
            if (firstOkChar == -1) firstOkChar = i
          }
        }
      }
    }
    if (s == "" || firstOkChar == -1) ""
    else
      s.substring(firstOkChar, if (finalChar == -1) lastOkChar + 1 else finalChar).map { x =>
        if (!legal(x)) '_' else x
      }
  }

  // Summons correct IdentifierProposer to generate a proposal
  def getProposal[T](obj: T): String = {
    obj match {
      case i: HasCustomIdentifier => i.customDefinitionIdentifier // First give precedence to custom identifiers
      case b: chisel3.experimental.BaseModule => b.definitionIdentifier // Then to the one generated by the plugin
      case l: Iterable[_] => makeProposal(l.toList.map(getProposal): _*) // Handle iterables automatically
      case _ => filterProposal(obj.toString)
    }
  }

  // Algorithm to create an identifier proposal derived from a list of proposals
  def makeProposal(proposals: String*): String = proposals.filter(_ != "").mkString("_")
}

// Accessor for Chisels internals
private[chisel3] final def _getSourceLocator: SourceInfo = _sourceInfo

// Used with chisel3.naming.fixTraitIdentifier
protected def _traitModuleDefinitionIdentifierProposal: Option[String] = None

protected def _moduleDefinitionIdentifierProposal = {
  val baseName = _traitModuleDefinitionIdentifierProposal.getOrElse(this.getClass.getName)

  /* A sequence of string filters applied to the name */
  val filters: Seq[String => String] =
    Seq(
      ((a: String) => raw"\$$+anon".r.replaceAllIn(a, "_Anon")) // Merge the "$$anon" name with previous name
    )

  filters
    .foldLeft(baseName) { case (str, filter) => filter(str) } // 1. Apply filters to baseName
    .split("\\.|\\$") // 2. Split string at '.' or '$'
    .filterNot(_.forall(_.isDigit)) // 3. Drop purely numeric names
    .last // 4. Use the last name
}
// Needed this to override identifier for DefinitionClone
private[chisel3] def _definitionIdentifier = {
  val madeProposal = chisel3.naming.IdentifierProposer.makeProposal(this._moduleDefinitionIdentifierProposal)
  Builder.globalIdentifierNamespace.name(madeProposal)
}

/** Represents an eagerly-determined unique and descriptive identifier for this module */
final val definitionIdentifier = _definitionIdentifier

// Modules that contain bodies should override this.
protected def hasBody:        Boolean = false
protected val _body:          Block = if (hasBody) new Block(_sourceInfo) else null
private[chisel3] def getBody: Option[Block] = Some(_body)

